8	export async function addTodoWithDb(
9	  database: ReturnType<typeof createDb>,
10	  title: string
11	) {
12	  const trimmed = title.trim();
13	  if (!trimmed) return;
14	
15	  database.insert(todos).values({ title: trimmed }).run();
16	  revalidatePath("/");
17	}
18	
19	export async function addTodo(formData: FormData) {
20	  const title = formData.get("title") as string;
21	  await addTodoWithDb(db, title ?? "");
22	}
23	
24	export async function toggleTodoWithDb(
25	  database: ReturnType<typeof createDb>,
26	  id: number
27	) {
28	  const existing = database
29	    .select()
30	    .from(todos)
31	    .where(eq(todos.id, id))
32	    .all();
33	  if (existing.length === 0) return;
34	
35	  const current = existing[0].completed;
36	  database
37	    .update(todos)
38	    .set({ completed: current === 0 ? 1 : 0 })
39	    .where(eq(todos.id, id))
40	    .run();
41	  revalidatePath("/");
42	}
43	
44	export async function toggleTodo(formData: FormData) {
45	  const id = Number(formData.get("id"));
46	  await toggleTodoWithDb(db, id);
47	}
48	
49	export async function deleteTodoWithDb(
50	  database: ReturnType<typeof createDb>,
51	  id: number
52	) {
53	  database.delete(todos).where(eq(todos.id, id)).run();
54	  revalidatePath("/");
55	}
56	
57	export async function deleteTodo(formData: FormData) {
58	  const id = Number(formData.get("id"));
59	  await deleteTodoWithDb(db, id);
60	}
